BEGIN;

DROP TABLE IF EXISTS customers;

CREATE TABLE customers (
    "customer_id" VARCHAR(255),
    "first_name" VARCHAR(255),
    "last_name" VARCHAR(255),
    "gender" VARCHAR(255),
    "age" INTEGER,
    "city" VARCHAR(255),
    "state" VARCHAR(255),
    "country" VARCHAR(255),
    "annual_income" NUMERIC(18,2),
    "customer_segment" VARCHAR(255),
    "account_open_date" VARCHAR(255),
    "risk_score" INTEGER,
    "preferred_spending_min" NUMERIC(18,2),
    "preferred_spending_max" NUMERIC(18,2),
    "preferred_city" VARCHAR(255),
    "preferred_country" VARCHAR(255),
    "trusted_device_id" VARCHAR(255),
    "card_number" VARCHAR(255),
    "card_type" VARCHAR(255),
	"email" VARCHAR(255),
	"transaction_limit"  NUMERIC(18,2),
    "update_timestamp" TIMESTAMP
);

